    68→    eventModalView({
    69→      content_id: 'menu_header',
    70→      location_1: 'monetizacao',
    71→      location_2: 'hub_recompensas_spmais',
    72→      location_3: 'home_hub_recompensas',
    73→    });
    74→  };
    75→
    76→  const buildPointsCardItems = useCardBuilderWhereUseMyPoints();
    77→
    78→  const requestPointsCallback = useCallback(() => {
    79→    requestPointsBalance();
    80→    requestPointsProducts();
    81→    getParameterPointsProgram();
    82→  }, [
    83→    requestPointsBalance,
    84→    requestPointsProducts,
    85→  ]);
    86→
    87→  const handleApiErrorPress = useCallback(() => {
    88→    if (isErrorBalance || isErrorProducts) {
    89→      requestPointsCallback();
    90→    }
    91→  }, [
    92→    isErrorBalance,
    93→    isErrorProducts,
    94→    requestPointsCallback,
    95→  ]);
    96→
    97→  useFocusEffect(
    98→    useCallback(() => {
    99→      if (!hasFocused.current) {
   100→        eventScreenViewV3(
   101→          'home_hub_recompensas',
   102→          'hub_recompensas_spmais',
